    $zh$[]$zh$::jsonb,
    $zh${"category":"business","categoryLabel":"Business & Investment","episodeNo":"04","rev":"01","seriesNav":[{"no":"01","label":"签证体系与个体经营路径"},{"no":"02","label":"行业选择与加盟"},{"no":"03","label":"五阶段移居流程"},{"no":"04","label":"永久居留与定居","active":true}],"title":"外国企业主在韩国的永久居留 —— F-2-99、家属、不动产与定居（2026）","ogTitle":"从 D-9 到 F-2-99：外国企业主在韩国的永久居留（2026）","url":"外国企业主韩国永久居留-F-2-99到F-5指南-2026","lang":"zh","translation_group":"biz-immigration-ep4","translations":{"en":"permanent-residency-korea-foreign-business-owner-2026","zh":"外国企业主韩国永久居留-F-2-99到F-5指南-2026"},"disclaimer":"本系列第 4 集，也是终篇。第 1 至 3 集介绍了 D-9-4 与 D-9-5 签证体系、行业与加盟选择逻辑，以及实际的移居与开业流程。本集讨论在韩定居后的长期视野。","metaDescription":"D-9-4 或 D-9-5 签证发给后，定居才刚刚开始 —— 而这是一段长程。停留期间延长、F-2-99 长期居留转换、F-3 家属、子女大学入学、不动产购置、商业楼宇租赁保护法、公共医疗，以及在外国个体经营者上同等适用的韩国小工商业支援（2026）。","series":"Episode 4 · 商业移民系列","publishedAt":"2026.05.01","updatedAt":"2026.05.06","readingMin":14,"sections":[{"id":"s1","heading":"取得签证才是真正旅程的开始","blocks":[{"type":"p","text":"D-9-4 或 D-9-5 签证发给、入境韩国、店面开业的那一刻 —— 这<b>不是商业移民的终点，而是起点</b>。从那一刻起，韩国的长期居留开始，新的议题依次展开：停留期间延长、家属定居、子女教育、住房稳定、资产管理，以及一定时间后向长期居留签证的转换。本集概述这一阶段哪些法律体系在运作，以及应当提前准备什么。"},{"type":"p","text":"Lawyeon 出入境·移民支援中心不仅支持商业移民的初期移居与开业阶段。通过我们的后续支持协议，我们就<b>移居后的居留、家属、资产与纠纷</b>提供持续的长期法律咨询。本集涉及的所有主题都属于这一后续支持范围。"}]},{"id":"s2","heading":"D-9 停留期间延长 —— 评判的是业务是否“鲜活”","blocks":[{"type":"p","text":"无论 D-9-4 还是 D-9-5，初次居留期通常为 1 年，要在韩国继续居留必须在到期前办理延长。延长申请<b>可在到期前 4 个月开始提交</b>，最迟应在到期前 2 个月之前完成提交。"},{"type":"p","text":"出入境管理事务所在延长审查时考查的核心归结为一点：<b>业务是否实际运营</b>。具体而言，评估四项内容："},{"type":"table","title":"D-9 延长审查的四项内容","headers":["项目","支持文件"],"rows":[["营业收入实绩","纳税证明"],["营业场所维持","商铺租约、能证明门店实际经营的文件"],["居住维持","住宅租约、住宿提供确认书或其他居住证明"],["雇佣状况","雇佣相关文件"]]},{"type":"p","text":"当所有这些要素稳定积累时，延长就会顺利推进。延长本身是后续支持的核心任务。从最早的定居阶段开始，我们律师事务所就与客户一起设计营业证据、纳税记录与业务运营文件的记录体系；延长期临近时，我们准备并提交申请文件，并处理出入境管理事务所的询问。"}]},{"id":"s3","heading":"向 F-2-99 长期居留签证的转换","blocks":[{"type":"p","text":"维持 D-9 居留 5 年以上后，向 <b>F-2-99 长期居留签证</b>的路径打开。这是在维持同一业务的同时将居留资格变更为长期居留的程序。"},{"type":"p","text":"F-2-99 转换审查的评估内容与 D-9 延长审查不同。D-9 延长问的是“业务是否鲜活？”F-2-99 转换问的是<b>申请人是否稳定融入了韩国社会</b>。具体评估四个领域："},{"type":"table","title":"F-2-99 转换审查 · 四个评估领域","headers":["领域","内容"],"rows":[["居住","是否已确保适合长期居留的住所"],["品行","出入境管理法违规、一般刑事处罚或税务拖欠是否超过一定阈值"],["收入与资产","资产 2,000 万韩元以上；年度业务收入 4,000 万韩元以上"],["韩语能力与文化理解","KIIP 4 级以上，或韩国大学毕业"]],"note":"具体评估标准可能调整，申请时需再次确认。"},{"type":"callout","text":"关键在于<b>从 D-9 居留期间起就设计生活，让这些领域自然积累</b>。这不是 5 年后突然能准备出来的事。"},{"type":"p","text":"关于术语的一点说明：F-2-99 严格意义上还不是永久居留权。它是通往 <b>F-5（永久居留权）</b>的长期居留资格，F-5 通常在 F-2-99 上再经过若干年、收入稳定、品行良好、业务持续运营的情况下方可考虑申请。对于外国企业主而言，F-2-99 标志着从 D-9 时期“以业务为条件”的居留 —— 即签证因业务表现而存续 —— 转向“以人生阶段为条件”的居留 —— 即在韩居留的依据从单一业务转向申请人在韩的整体生活。F-5 是计划长期定居者在此后的下一个里程碑。"}]},{"id":"s4","heading":"家属定居 —— F-3 身份下展开的内容","blocks":[{"type":"p","text":"如第 2、第 3 集所述，D-9 持有人邀请配偶与未成年子女赴韩时，家属获得 <b>F-3（同伴家属）身份</b>。F-3 实际运作中最常遇到的三个情形如下。"},{"type":"numbered","label":"MATTER","items":[{"n":1,"title":"配偶就业限制","text":"F-3 身份原则上限制就业。如果配偶希望在韩国就业，须考虑变更为单独的居留资格。根据配偶的学历与履历背景，可能可转向 E-7（特定活动）等。如果配偶希望自行创业，也存在满足 D-9-4 要求并转向独立个体经营资格的路径。任何路径都需要具体的资格条件与文件准备，因此事先审视很有必要。"},{"n":2,"title":"子女学校就读","text":"学龄子女可入读韩国公立或私立的小学、中学和高中。原则是通过居住地所在教育厅分配，外国学生韩语预备课程在公立学校另行提供。私立学校遵循各校自身的转学录取标准。"},{"n":3,"title":"停留期间挂钩","text":"F-3 停留期间与主申请人（D-9 持有人）的停留期间挂钩。主申请人获得延长时，F-3 一并延长；主申请人转向 F-2-99 时，家属的 F-3 居留与该转换的稳定性挂钩。"}]}]},{"id":"s-cta-mid","type":"midCta","blocks":[]},{"id":"s6","heading":"外国人购置韩国不动产 —— 几乎没有限制的法律框架","blocks":[{"type":"p","text":"外国人在韩国购置不动产<b>几乎没有法律或法规上的限制</b>。基本税务框架与韩国国民相同。购置时的取得税、保有期间的财产税与综合不动产税、出售时的转让所得税都按与韩国人相同的结构课征。不基于国籍课征单独的附加税；但以居留为前提的特别条款 —— 如一户一房免税 —— 可能因所持居留资格的形式而适用方式不同。"},{"type":"p","text":"购置住宅不动产时，<b>抵押融资</b>结构与韩国人可获得的并无实质差异。但除担保价值外，韩国境内的收入与资产证明文件是核心审查材料，因此当营业执照办理后稳定积累营业收入与税务申报时，扩展额度更受青睐。我们律师事务所将目标物业的产权分析、合同审阅与相关税务分析纳入<b>综合咨询范围</b>。"}]},{"id":"s7","heading":"《商业楼宇租赁保护法》如何保护外国店主","blocks":[{"type":"p","text":"在以商铺承租人身份经营业务时，韩国《商业楼宇租赁保护法》为店主提供两项重要保护机制：<b>请求合同更新的权利</b>与<b>恢复权利金（권리금）机会的保护</b>。"},{"type":"callout","text":"这两项保护机制<b>对外国店主与韩国店主同等适用</b>。《商业楼宇租赁保护法》不基于承租人的国籍区分适用。但在折算押金超过法定阈值的大型商业空间情况下，部分条款适用受限，因此在签约阶段需要核实是否适用。"}]},{"id":"s8","heading":"社会保险 —— 与韩国国民相同的基本框架","blocks":[{"type":"p","text":"在韩国社会保险体系中，国民健康保险<b>与对韩国国民相同的基本框架</b>对外国人自动适用。作为业务经营者，您按地区被保险人身份缴纳保险费；雇佣员工后，转为以工作单位为基础的被保险人身份。在韩居留<b>满 6 个月以上</b>后，地区被保险人身份自动适用。F-3 同伴家属身份的家属同样适用。"},{"type":"p","text":"外国企业主获得在本国通常无法接触的公共医疗保健。通过健康保险参保，本人与家属的医疗费用负担在体系层面降低 —— 这是支撑长期业务运营的生活稳定要素之一。"}]},{"id":"s9","heading":"韩国小工商业支援对外国个体经营者同等适用","blocks":[{"type":"p","text":"在不动产与租赁法的法律保护以及社会保险框架之外，定居韩国的外国企业主还能接触一类常被忽视的公共资源：韩国的<b>小工商业支援生态</b>。"},{"type":"p","text":"韩国政府为小工商业者运营一系列项目，包括低利率政策贷款、担保支持的融资、业务稳定补助金、紧急援助资金。这些项目由<b>韩国小工商业市场振兴公团（SEMAS）</b>依据《小工商业基本法》管理。<b>国籍并非区分因素：任何符合法定小工商业标准 —— 例如雇员人数门槛 —— 的个体经营者，无论韩国人还是外国人，都按相同条件享有资格。</b>已完成个体工商户登记的外国人，按与韩国小工商业者相同的条件，享有相同的支援。"},{"type":"callout","text":"法律框架本身不区分外国与本国个体经营者 —— 两者都被纳入相同的“小工商业”类别。在实际操作中，这意味着已定居的外国经营者可获得在本国通常无法接触的公共资源：用于流动资金的低利率融资、政府支持的担保、业务低迷期的支援。这些项目不仅在开业时可用，在业务的整个生命周期都可用 —— 包括本集涉及的、居留从 D-9 转向 F-2-99 及之后的时期。"}]},{"id":"s10","heading":"后续支持协议涵盖的领域","blocks":[{"type":"p","text":"上述所有主题都属于本所<b>后续支持协议</b>的范围。"},{"type":"numbered","label":"SCOPE","items":[{"n":1,"title":"居留资格管理","text":"D-9 停留期间延长、向 F-2-99 长期居留签证的转换"},{"n":2,"title":"家属居留管理","text":"F-3 延长、配偶资格变更、与子女教育相关的居留事项"},{"n":3,"title":"纠纷解决","text":"与加盟总部的合同纠纷、与房东的商铺租赁纠纷、与员工的劳动合同纠纷"},{"n":4,"title":"合同审阅","text":"加盟合同更新与解除、商铺租约更新与权利金恢复、劳动合同执行"},{"n":5,"title":"不动产咨询","text":"住宅与商业不动产购置与出售的产权分析与申报义务"},{"n":6,"title":"税务咨询","text":"个体经营者税务问题审视、不动产税务分析"}]},{"type":"p","text":"后续支持协议并非每位客户都必须签订。可在所需的范围与所需的时点选择签订，针对特定事项的单次咨询同样可用。"}]},{"id":"closing","heading":"定居是长程的事业","blocks":[{"type":"p","text":"如果说第 1 至 3 集讨论的是<b>韩国商业移民的开始</b>，那么第 4 集讨论的是<b>定居的开始</b>。本集传达的核心视角是：取得签证不是项目的终点 —— 它是一段长程的起点。两年周期的居留延长。五年的 F-2-99 转换，以及随后的 F-5 永久居留权里程碑。十年的商铺租约稳定段。《商业楼宇租赁保护法》与公共医疗保健体系的法律保护。对外国个体经营者按与韩国国民相同条件适用的小工商业支援项目。期间持续不断的家属定居与资产积累。"},{"type":"p","text":"纵观本系列四集，我们涵盖了：为何 D-9-4 与 D-9-5 是适合外国个体经营商业移民韩国的签证（第 1 集）；如何选择行业、为何加盟提供最具可预测性的路径（第 2 集）；从预先咨询到后续支持的五阶段流程（第 3 集）；以及签证发给后开始的长期视野（本集）。韩国商业移民很少是单一事件 —— 它是多年间复合积累的一系列决定。在早期就设计这些决定，并一同走完，正是我们所做的工作。"},{"type":"p","text":"Lawyeon 出入境·移民支援中心由 Lawyeon 律师事务所的资深律师、口译协调员与创业移民专家组成，专门支持外国人通过 D-9-4 与 D-9-5 进行个体经营商业移民。预先咨询免费，申请人可直接从本国通过我们的咨询线程提出咨询。"}]}],"related":[{"tag":"EP 1","title":"外国人如何在韩国创业 — D-9-4、D-9-5 与个体经营签证完全指南（2026）","url":"外国人在韩国创业-D-9-4-D-9-5签证完全指南-2026"},{"tag":"EP 2","title":"外国人在韩国应该开什么加盟店？行业、品牌与信息公开书（2026）","url":"外国人在韩国开加盟店-行业品牌指南-2026"},{"tag":"EP 3","title":"外国人在韩国开店流程 —— 从预先咨询到开业当天的 2026 年五阶段完整指南","url":"外国人在韩国开店流程-五阶段完整指南-2026"}]}$zh$::jsonb,
    NOW(),
    NOW()
  )
